import{_ as i,c as l,o as t,V as a}from"./chunks/framework.CsbsVE7l.js";const m=JSON.parse('{"title":"Antigravity AI 模型选用指南","description":"","frontmatter":{"outline":"deep","editLink":false},"headers":[],"relativePath":"efficiency/ai/antigravity-ai-model.md","filePath":"efficiency/ai/antigravity-ai-model.md","lastUpdated":1773715144000}'),e={name:"efficiency/ai/antigravity-ai-model.md"},n=a('<h1 id="antigravity-ai-模型选用指南" tabindex="-1">Antigravity AI 模型选用指南 <a class="header-anchor" href="#antigravity-ai-模型选用指南" aria-label="Permalink to &quot;Antigravity AI 模型选用指南&quot;">​</a></h1><blockquote><p>本文档整理了当前可用的 AI 模型的优势、劣势及适用场景，方便团队根据不同需求灵活选用。</p></blockquote><hr><h2 id="gemini-3-1-pro-high-new" tabindex="-1">Gemini 3.1 Pro (High) <code>New</code> <a class="header-anchor" href="#gemini-3-1-pro-high-new" aria-label="Permalink to &quot;Gemini 3.1 Pro (High) `New`&quot;">​</a></h2><p><strong>优势</strong></p><ul><li>超强的长上下文理解，支持海量代码库分析</li><li>多模态能力强，可处理图片、截图等视觉输入</li><li>与 Google 生态整合良好</li><li>工具调用（Tool Call）成功率高</li></ul><p><strong>劣势</strong></p><ul><li>响应速度较慢</li><li>对需要&quot;深度推理&quot;的复杂逻辑题，不如 Thinking 系列</li></ul><p><strong>适合场景</strong></p><ul><li>大型代码库重构、多文件跨模块分析</li><li>UI 截图理解、长文档处理</li><li>需要调用大量外部工具的自动化任务</li></ul><hr><h2 id="gemini-3-1-pro-low-new" tabindex="-1">Gemini 3.1 Pro (Low) <code>New</code> <a class="header-anchor" href="#gemini-3-1-pro-low-new" aria-label="Permalink to &quot;Gemini 3.1 Pro (Low) `New`&quot;">​</a></h2><p><strong>优势</strong></p><ul><li>比 High 版本响应速度更快，成本更低</li><li>日常开发任务综合表现良好</li></ul><p><strong>劣势</strong></p><ul><li>在超复杂、高精度任务上略逊于 High 版</li></ul><p><strong>适合场景</strong></p><ul><li>日常代码问答、简单 Bug 修复</li><li>快速生成模板代码、单文件修改</li></ul><hr><h2 id="gemini-3-flash" tabindex="-1">Gemini 3 Flash <a class="header-anchor" href="#gemini-3-flash" aria-label="Permalink to &quot;Gemini 3 Flash&quot;">​</a></h2><p><strong>优势</strong></p><ul><li>极速响应，适合高频交互</li><li>Token 消耗少，成本最低</li></ul><p><strong>劣势</strong></p><ul><li>模型能力相对有限，复杂任务表现较弱</li></ul><p><strong>适合场景</strong></p><ul><li>快速问答、简单代码补全</li><li>轻量脚本生成，对速度有强烈要求时</li></ul><hr><h2 id="claude-sonnet-4-6-thinking" tabindex="-1">Claude Sonnet 4.6 (Thinking) <a class="header-anchor" href="#claude-sonnet-4-6-thinking" aria-label="Permalink to &quot;Claude Sonnet 4.6 (Thinking)&quot;">​</a></h2><p><strong>优势</strong></p><ul><li>带思维链（Chain of Thought）推理，代码质量极高</li><li>对 UI/CSS 审美细节把控能力强</li><li>逻辑严谨，对边界情况处理较好</li></ul><p><strong>劣势</strong></p><ul><li>响应较慢（需要思考时间）</li><li>上下文窗口比 Gemini 系列小</li></ul><p><strong>适合场景</strong></p><ul><li><strong>UI/UX 页面重构</strong>（首选）</li><li>复杂业务逻辑实现、高质量前端组件开发</li><li>需要高代码质量输出的场景</li></ul><hr><h2 id="claude-opus-4-6-thinking" tabindex="-1">Claude Opus 4.6 (Thinking) <a class="header-anchor" href="#claude-opus-4-6-thinking" aria-label="Permalink to &quot;Claude Opus 4.6 (Thinking)&quot;">​</a></h2><p><strong>优势</strong></p><ul><li>Claude 系列最强模型，推理能力顶级</li><li>适合最复杂的架构设计，代码正确率最高</li></ul><p><strong>劣势</strong></p><ul><li>速度最慢、成本最高</li><li>简单任务&quot;大材小用&quot;</li></ul><p><strong>适合场景</strong></p><ul><li>系统架构设计、复杂算法实现</li><li>需要多步推理的技术难题</li></ul><hr><h2 id="gpt-oss-120b-medium" tabindex="-1">GPT-OSS 120B (Medium) <a class="header-anchor" href="#gpt-oss-120b-medium" aria-label="Permalink to &quot;GPT-OSS 120B (Medium)&quot;">​</a></h2><p><strong>优势</strong></p><ul><li>开源模型，隐私性更好，数据不出本地</li><li>成本可控，代码能力均衡</li></ul><p><strong>劣势</strong></p><ul><li>综合能力弱于上面的旗舰模型</li><li>在极复杂任务上与商业模型有一定差距</li></ul><p><strong>适合场景</strong></p><ul><li>对数据隐私有要求的场景</li><li>日常代码生成、简单功能实现</li></ul><hr><h2 id="快速选型表" tabindex="-1">快速选型表 <a class="header-anchor" href="#快速选型表" aria-label="Permalink to &quot;快速选型表&quot;">​</a></h2><table><thead><tr><th>需求场景</th><th>推荐模型</th></tr></thead><tbody><tr><td>UI/UX 页面重构</td><td>Claude Sonnet 4.6 (Thinking)</td></tr><tr><td>大型代码库分析 / 架构梳理</td><td>Gemini 3.1 Pro (High)</td></tr><tr><td>日常 Bug 修复 / 快速问答</td><td>Gemini 3.1 Pro (Low) 或 3 Flash</td></tr><tr><td>最复杂的业务架构设计</td><td>Claude Opus 4.6 (Thinking)</td></tr><tr><td>隐私敏感或本地化场景</td><td>GPT-OSS 120B (Medium)</td></tr></tbody></table>',53),o=[n];function r(s,d,u,h,g,p){return t(),l("div",null,o)}const _=i(e,[["render",r]]);export{m as __pageData,_ as default};
